import "server-only";

import { Knock } from "@knocklabs/node";

export function getKnockClient() {
  return new Knock({
    apiKey: process.env.KNOCK_API_KEY,
  });
}

export type TriggerKnockWorkflowInput = {
  workflowKey: string;
  recipients: string[];
  data?: Record<string, unknown>;
};

export async function triggerKnockWorkflow({
  workflowKey,
  recipients,
  data = {},
}: TriggerKnockWorkflowInput) {
  if (recipients.length === 0) {
    throw new Error("Knock workflow trigger requires at least one recipient.");
  }

  return getKnockClient().workflows.trigger(workflowKey, {
    recipients,
    data,
  });
}

"use client";

import { KnockFeedProvider, KnockProvider } from "@knocklabs/react";
import type { ReactNode } from "react";

type KnockInboxProviderProps = {
  userId: string;
  children: ReactNode;
};

export function KnockInboxProvider({ userId, children }: KnockInboxProviderProps) {
  const apiKey = process.env.NEXT_PUBLIC_KNOCK_PUBLIC_API_KEY;
  const feedId = process.env.NEXT_PUBLIC_KNOCK_FEED_CHANNEL_ID;

  if (!apiKey || !feedId) {
    return children;
  }

  return (
    <KnockProvider apiKey={apiKey} user={{ id: userId }}>
      <KnockFeedProvider feedId={feedId}>{children}</KnockFeedProvider>
    </KnockProvider>
  );
}

const checks = [
  "Create a Knock environment and in-app feed channel.",
  "Add server and public Knock environment variables.",
  "Wrap the authenticated app shell after user identity is available.",
  "Trigger workflows from server code only.",
  "Verify read/unread state and preferences with a test user.",
];

export default function KnockNotificationsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Knock Notifications</h1>
        <p className="text-muted-foreground">
          Optional hosted in-app feed and workflow adapter for the notification core.
        </p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">
            {check}
          </div>
        ))}
      </div>
    </main>
  );
}
